class LoggerAdapter(logging.LoggerAdapter):
    """Custom adapter that injects request context into log records."""

    def process(self, msg, kwargs):
        extra = kwargs.get("extra", {})
        if "request_id" in self.extra:
            extra["request_id"] = self.extra["request_id"]
        if "user_id" in self.extra:
            extra["user_id"] = self.extra["user_id"]
        kwargs["extra"] = extra
        return msg, kwargs


def get_logger(name, request_id=None, user_id=None):
    """
    Get a logger instance with optional request context.

    Args:
        name: Logger name (e.g., 'application.database')
        request_id: Optional request tracking ID
        user_id: Optional user identifier

    Returns:
        Logger or LoggerAdapter instance
    """
    logger = logging.getLogger(name)
    if request_id or user_id:
        extra = {}
        if request_id:
            extra["request_id"] = request_id
        if user_id:
            extra["user_id"] = user_id
        return LoggerAdapter(logger, extra)
    return logger


